export type Category = 'length' | 'weight' | 'temperature' | 'volume' | 'time'

export type UnitDefinition = {
  symbol: string
  name: string
  toBase: (v: number) => number
  fromBase: (v: number) => number
  formulaToBase: string
  formulaFromBase: string
}

export type ConversionResult = {
  category: Category
  fromUnit: string
  toUnit: string
  inputValue: number
  outputValue: number
  formula: string
}

const lengthUnits: Record<string, UnitDefinition> = {
  mm:  { symbol: 'mm',  name: 'Millimeters', toBase: (v) => v / 1000,        fromBase: (v) => v * 1000,        formulaToBase: 'v / 1000',          formulaFromBase: 'v × 1000' },
  cm:  { symbol: 'cm',  name: 'Centimeters',  toBase: (v) => v / 100,         fromBase: (v) => v * 100,         formulaToBase: 'v / 100',           formulaFromBase: 'v × 100' },
  m:   { symbol: 'm',   name: 'Meters',       toBase: (v) => v,               fromBase: (v) => v,               formulaToBase: 'v',                 formulaFromBase: 'v' },
  km:  { symbol: 'km',  name: 'Kilometers',   toBase: (v) => v * 1000,        fromBase: (v) => v / 1000,        formulaToBase: 'v × 1000',          formulaFromBase: 'v / 1000' },
  in:  { symbol: 'in',  name: 'Inches',       toBase: (v) => v * 0.0254,      fromBase: (v) => v / 0.0254,      formulaToBase: 'v × 0.0254',        formulaFromBase: 'v / 0.0254' },
  ft:  { symbol: 'ft',  name: 'Feet',         toBase: (v) => v * 0.3048,      fromBase: (v) => v / 0.3048,      formulaToBase: 'v × 0.3048',        formulaFromBase: 'v / 0.3048' },
  yd:  { symbol: 'yd',  name: 'Yards',        toBase: (v) => v * 0.9144,      fromBase: (v) => v / 0.9144,      formulaToBase: 'v × 0.9144',        formulaFromBase: 'v / 0.9144' },
  mi:  { symbol: 'mi',  name: 'Miles',        toBase: (v) => v * 1609.344,    fromBase: (v) => v / 1609.344,    formulaToBase: 'v × 1609.344',      formulaFromBase: 'v / 1609.344' },
}

const weightUnits: Record<string, UnitDefinition> = {
  mg:  { symbol: 'mg',  name: 'Milligrams', toBase: (v) => v / 1000,        fromBase: (v) => v * 1000,        formulaToBase: 'v / 1000',          formulaFromBase: 'v × 1000' },
  g:   { symbol: 'g',   name: 'Grams',      toBase: (v) => v,               fromBase: (v) => v,               formulaToBase: 'v',                 formulaFromBase: 'v' },
  kg:  { symbol: 'kg',  name: 'Kilograms',  toBase: (v) => v * 1000,        fromBase: (v) => v / 1000,        formulaToBase: 'v × 1000',          formulaFromBase: 'v / 1000' },
  lb:  { symbol: 'lb',  name: 'Pounds',     toBase: (v) => v * 453.592,     fromBase: (v) => v / 453.592,     formulaToBase: 'v × 453.592',       formulaFromBase: 'v / 453.592' },
  oz:  { symbol: 'oz',  name: 'Ounces',     toBase: (v) => v * 28.3495,     fromBase: (v) => v / 28.3495,     formulaToBase: 'v × 28.3495',       formulaFromBase: 'v / 28.3495' },
}

const temperatureUnits: Record<string, UnitDefinition> = {
  C: { symbol: '°C', name: 'Celsius',    toBase: (v) => v,               fromBase: (v) => v,                     formulaToBase: 'v',                     formulaFromBase: 'v' },
  F: { symbol: '°F', name: 'Fahrenheit', toBase: (v) => (v - 32) * 5/9,  fromBase: (v) => v * 9/5 + 32,          formulaToBase: '(v - 32) × 5/9',       formulaFromBase: 'v × 9/5 + 32' },
  K: { symbol: 'K',  name: 'Kelvin',     toBase: (v) => v - 273.15,      fromBase: (v) => v + 273.15,            formulaToBase: 'v - 273.15',            formulaFromBase: 'v + 273.15' },
}

const volumeUnits: Record<string, UnitDefinition> = {
  ml:   { symbol: 'ml',   name: 'Milliliters',  toBase: (v) => v,                fromBase: (v) => v,                formulaToBase: 'v',               formulaFromBase: 'v' },
  l:    { symbol: 'l',    name: 'Liters',        toBase: (v) => v * 1000,         fromBase: (v) => v / 1000,         formulaToBase: 'v × 1000',        formulaFromBase: 'v / 1000' },
  gal:  { symbol: 'gal',  name: 'Gallons',       toBase: (v) => v * 3785.41,      fromBase: (v) => v / 3785.41,      formulaToBase: 'v × 3785.41',     formulaFromBase: 'v / 3785.41' },
  qt:   { symbol: 'qt',   name: 'Quarts',        toBase: (v) => v * 946.353,      fromBase: (v) => v / 946.353,      formulaToBase: 'v × 946.353',     formulaFromBase: 'v / 946.353' },
  pt:   { symbol: 'pt',   name: 'Pints',         toBase: (v) => v * 473.176,      fromBase: (v) => v / 473.176,      formulaToBase: 'v × 473.176',     formulaFromBase: 'v / 473.176' },
  cup:  { symbol: 'cup',  name: 'Cups',          toBase: (v) => v * 236.588,      fromBase: (v) => v / 236.588,      formulaToBase: 'v × 236.588',     formulaFromBase: 'v / 236.588' },
  tbsp: { symbol: 'tbsp', name: 'Tablespoons',   toBase: (v) => v * 14.7868,      fromBase: (v) => v / 14.7868,      formulaToBase: 'v × 14.7868',     formulaFromBase: 'v / 14.7868' },
  tsp:  { symbol: 'tsp',  name: 'Teaspoons',     toBase: (v) => v * 4.92892,      fromBase: (v) => v / 4.92892,      formulaToBase: 'v × 4.92892',     formulaFromBase: 'v / 4.92892' },
}

const timeUnits: Record<string, UnitDefinition> = {
  ms:   { symbol: 'ms',   name: 'Milliseconds', toBase: (v) => v / 1000,           fromBase: (v) => v * 1000,           formulaToBase: 'v / 1000',        formulaFromBase: 'v × 1000' },
  s:    { symbol: 's',    name: 'Seconds',      toBase: (v) => v,                  fromBase: (v) => v,                  formulaToBase: 'v',               formulaFromBase: 'v' },
  min:  { symbol: 'min',  name: 'Minutes',      toBase: (v) => v * 60,             fromBase: (v) => v / 60,             formulaToBase: 'v × 60',          formulaFromBase: 'v / 60' },
  hr:   { symbol: 'hr',   name: 'Hours',        toBase: (v) => v * 3600,           fromBase: (v) => v / 3600,           formulaToBase: 'v × 3600',        formulaFromBase: 'v / 3600' },
  day:  { symbol: 'day',  name: 'Days',         toBase: (v) => v * 86400,          fromBase: (v) => v / 86400,          formulaToBase: 'v × 86400',       formulaFromBase: 'v / 86400' },
  week: { symbol: 'week', name: 'Weeks',        toBase: (v) => v * 604800,         fromBase: (v) => v / 604800,         formulaToBase: 'v × 604800',      formulaFromBase: 'v / 604800' },
}

export const unitsByCategory: Record<Category, Record<string, UnitDefinition>> = {
  length: lengthUnits,
  weight: weightUnits,
  temperature: temperatureUnits,
  volume: volumeUnits,
  time: timeUnits,
}

export const categories: { key: Category; label: string }[] = [
  { key: 'length', label: 'Length' },
  { key: 'weight', label: 'Weight' },
  { key: 'temperature', label: 'Temperature' },
  { key: 'volume', label: 'Volume' },
  { key: 'time', label: 'Time' },
]

const buildFormula = (
  fromDef: UnitDefinition,
  toDef: UnitDefinition,
  category: Category,
): string => {
  if (category === 'temperature') {
    return buildTemperatureFormula(fromDef.symbol, toDef.symbol)
  }
  const baseName = category === 'length' ? 'm'
    : category === 'weight' ? 'g'
    : category === 'volume' ? 'ml'
    : 's'
  if (fromDef.symbol === toDef.symbol) return `${fromDef.name} = ${toDef.name}`
  return `${fromDef.name} → ${baseName} (${fromDef.formulaToBase}) → ${toDef.name} (${toDef.formulaFromBase})`
}

const buildTemperatureFormula = (from: string, to: string): string => {
  if (from === to) return 'No conversion needed'
  const formulas: Record<string, string> = {
    '°C→°F': '°F = °C × 9/5 + 32',
    '°F→°C': '°C = (°F - 32) × 5/9',
    '°C→K':  'K = °C + 273.15',
    'K→°C':  '°C = K - 273.15',
    '°F→K':  'K = (°F - 32) × 5/9 + 273.15',
    'K→°F':  '°F = (K - 273.15) × 9/5 + 32',
  }
  return formulas[`${from}→${to}`] ?? `${from} → ${to}`
}

const roundResult = (value: number): number => {
  if (Number.isInteger(value)) return value
  return Math.round(value * 1_000_000) / 1_000_000
}

export const convert = (
  category: Category,
  value: number,
  from: string,
  to: string,
): ConversionResult => {
  const units = unitsByCategory[category]
  const fromDef = units[from]
  const toDef = units[to]
  if (!fromDef || !toDef) {
    throw new Error(`Unknown unit: ${from} or ${to} in category ${category}`)
  }
  const baseValue = fromDef.toBase(value)
  const outputValue = roundResult(toDef.fromBase(baseValue))
  const formula = buildFormula(fromDef, toDef, category)
  return {
    category,
    fromUnit: from,
    toUnit: to,
    inputValue: value,
    outputValue,
    formula,
  }
}

