import { createSSR } from 'plaited'
import { convert, type Category, categories, unitsByCategory } from './convert.ts'
import { renderPage } from './view.ts'
import { appendHistory, readHistory } from './history.ts'

const ssr = createSSR()

const isValidCategory = (cat: string): cat is Category =>
  categories.some((c) => c.key === cat)

const htmlResponse = (body: string): Response =>
  new Response(
    `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Unit Converter</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8fafc; min-height: 100vh; padding: 40px 16px; }
  </style>
</head>
<body>${body}</body>
</html>`,
    { headers: { 'Content-Type': 'text/html; charset=utf-8' } },
  )

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url

  // GET / — render converter UI
  if (req.method === 'GET' && pathname === '/') {
    const cat = url.searchParams.get('category')
    const activeCategory: Category = cat && isValidCategory(cat) ? cat : 'length'
    const page = renderPage(activeCategory)
    const rendered = ssr(page)
    return htmlResponse(rendered)
  }

  // POST /convert — perform conversion
  if (req.method === 'POST' && pathname === '/convert') {
    const contentType = req.headers.get('content-type') ?? ''
    let category: string
    let value: number
    let from: string
    let to: string

    if (contentType.includes('application/json')) {
      const body = await req.json()
      category = body.category
      value = Number(body.value)
      from = body.from
      to = body.to
    } else {
      const formData = await req.formData()
      category = String(formData.get('category') ?? 'length')
      value = Number(formData.get('value'))
      from = String(formData.get('from') ?? '')
      to = String(formData.get('to') ?? '')
    }

    if (!isValidCategory(category)) {
      return jsonResponse({ error: `Invalid category: ${category}` }, 400)
    }
    if (isNaN(value)) {
      return jsonResponse({ error: 'Invalid value' }, 400)
    }
    const units = unitsByCategory[category]
    if (!units[from] || !units[to]) {
      return jsonResponse({ error: `Invalid unit: ${from} or ${to}` }, 400)
    }

    const result = convert(category, value, from, to)

    await appendHistory(result)

    // If form submission, re-render page with result
    if (!contentType.includes('application/json')) {
      const page = renderPage(category, result)
      const rendered = ssr(page)
      return htmlResponse(rendered)
    }

    return jsonResponse(result)
  }

  // GET /history — return recent conversions
  if (req.method === 'GET' && pathname === '/history') {
    const limit = Number(url.searchParams.get('limit') ?? 20)
    const history = await readHistory(limit)
    return jsonResponse(history)
  }

  return new Response('Not Found', { status: 404 })
}

import type { ConversionResult } from './convert.ts'

const DATA_PATH = './data/history.jsonl'

type HistoryEntry = ConversionResult & {
  timestamp: string
}

export const appendHistory = async (result: ConversionResult): Promise<void> => {
  const entry: HistoryEntry = {
    ...result,
    timestamp: new Date().toISOString(),
  }
  const line = JSON.stringify(entry) + '\n'
  const file = Bun.file(DATA_PATH)
  const existing = await file.exists() ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + line)
}

export const readHistory = async (limit = 20): Promise<HistoryEntry[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  const lines = text.trim().split('\n').filter(Boolean)
  return lines
    .slice(-limit)
    .reverse()
    .map((line) => JSON.parse(line) as HistoryEntry)
}

import { handleRequest } from './routes.ts'

const PORT = Number(process.env.PORT ?? 3000)

Bun.serve({
  port: PORT,
  fetch: handleRequest,
})

console.log(`Unit Converter running on http://localhost:${PORT}`)
